const body = $input.first().json.body || $input.first().json;
const mode = body.mode || 'ai'; // 'ai' or 'manual'
const description = body.description || '';
const name = body.name || '';
const product = body.product || 'endpoint';
const tactics = body.tactics || [];
const techniques = body.techniques || [];
const tools = body.tools || [];
const threat_actor = body.threat_actor || '';

return [{ json: { mode, description, name, product, tactics, techniques, tools, threat_actor, timestamp: new Date().toISOString() } }];

const input = $('Parse Input').item.json;

// Get the CALDERA library for grounding (if available)
let libraryContext = '';
try {
  const fs = require('fs');
  const lib = JSON.parse(fs.readFileSync('/data/scenarios/caldera-library.json', 'utf-8'));
  libraryContext = '\n\nExisting CALDERA adversaries you can reference: ' + 
    (lib.adversaries || []).map(a => a.adversary_id + ': ' + a.name).join(', ');
} catch(e) {}

const prompt = `You are a cybersecurity expert building attack simulation scenarios for Sophos Sales Engineers. Generate a complete, launchable attack scenario.

IMPORTANT RULES:
1. All PowerShell commands must be SAFE SIMULATIONS — use Write-Output to narrate what would happen, don't actually destroy data or exfiltrate real files
2. The PowerShell must work on Windows 11 with PowerShell 5.1+
3. Use real MITRE ATT&CK technique IDs (e.g., T1003.001, T1059.001)
4. The scenario must demonstrate techniques that Sophos ${input.product === 'endpoint' ? 'Endpoint/XDR' : input.product === 'ndr' ? 'NDR' : 'Firewall'} would detect

USER REQUEST:
${input.description}
${input.name ? 'Scenario name: ' + input.name : ''}
${input.tactics.length ? 'Tactics: ' + input.tactics.join(', ') : ''}
${input.tools.length ? 'Tools: ' + input.tools.join(', ') : ''}
${input.threat_actor ? 'Threat actor: ' + input.threat_actor : ''}
Product category: ${input.product}
${libraryContext}

Return ONLY valid JSON with this exact structure (no markdown, no backticks, just the JSON):
{
  "scenario": {
    "title": "Short descriptive title",
    "description": "2-3 sentence customer-facing description",
    "product": "${input.product}",
    "mitre_tactics": ["Tactic Name"],
    "mitre_techniques": [{"id": "T1xxx.xxx", "name": "Full technique name"}],
    "tools": ["tool1", "tool2"],
    "expected_detections": [{"detection": "What Sophos detects", "severity": "critical|high|medium"}],
    "talking_points": {
      "universal": ["Talking point 1 for customer conversations", "Talking point 2"]
    },
    "se_runbook": {
      "setup": "What the SE needs before running this",
      "steps": ["Step 1", "Step 2", "Step 3"],
      "talking_points_timing": "When to deliver talking points during the demo"
    }
  },
  "ability": {
    "tactic": "mitre-tactic-lowercase-hyphenated",
    "technique_id": "T1xxx.xxx",
    "technique_name": "Full technique name",
    "powershell": "Write-Output \\"=== SCENARIO NAME ===\\";\\nWrite-Output \\"[*] Step 1...\\";\\n# PowerShell simulation code here\\nWrite-Output \\"=== END ==="
  },
  "adversary": {
    "name": "Scenario title for CALDERA",
    "description": "Brief description"
  }
}

POWERSHELL GUIDELINES:
- Start with Write-Output "=== SCENARIO TITLE (technique ID) ==="
- Use [*] for actions, [+] for success, [-] for failures
- Narrate each step with Write-Output
- Use real Windows commands where safe (whoami, ipconfig, Get-Process, etc.)
- For dangerous operations, use [SIMULATED] prefix
- End with Write-Output "=== END SCENARIO ==="
- Separate commands with semicolons for single-line execution
- Keep it 10-30 lines`;

return [{ json: { prompt } }];

const fs = require('fs');
const https = require('https');
const http = require('http');
const prompt = $input.first().json.prompt;
let provider = 'ollama', apiKey = '', model = '';
try {
  const cfg = JSON.parse(fs.readFileSync('/data/scenarios/ai-config.json', 'utf-8'));
  provider = cfg.provider || 'ollama';
  apiKey = cfg.apiKey || '';
  model = cfg.model || '';
} catch(e) {
  provider = $env.AI_PROVIDER || 'ollama';
  apiKey = $env.AI_API_KEY || '';
  model = $env.AI_MODEL || '';
}
const defaults = { anthropic: 'claude-sonnet-4-20250514', openai: 'gpt-4o', gemini: 'gemini-2.5-flash', ollama: $env.OLLAMA_MODEL || 'llama3.2:3b' };
const useModel = model || defaults[provider] || defaults.ollama;
let url, headers, body;
switch (provider) {
  case 'anthropic':
    url = 'https://api.anthropic.com/v1/messages';
    headers = { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' };
    body = JSON.stringify({ model: useModel, max_tokens: 4096, messages: [{ role: 'user', content: prompt }] });
    break;
  case 'openai':
    url = 'https://api.openai.com/v1/chat/completions';
    headers = { 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
    body = JSON.stringify({ model: useModel, messages: [{ role: 'user', content: prompt }] });
    break;
  case 'gemini':
    url = 'https://generativelanguage.googleapis.com/v1beta/models/' + useModel + ':generateContent?key=' + apiKey;
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ contents: [{ parts: [{ text: prompt }] }] });
    break;
  default:
    url = ($env.OLLAMA_HOST || 'http://host.docker.internal:11434') + '/api/generate';
    headers = { 'Content-Type': 'application/json' };
    body = JSON.stringify({ model: useModel, prompt, stream: false });
}

const parsed = new URL(url);
const transport = parsed.protocol === 'https:' ? https : http;
const data = await new Promise((resolve, reject) => {
  const req = transport.request(url, { method: 'POST', headers, timeout: 120000 }, (res) => {
    let chunks = '';
    res.on('data', d => chunks += d);
    res.on('end', () => {
      if (res.statusCode >= 400) reject(new Error('AI provider error (' + provider + '): ' + res.statusCode + ' ' + chunks));
      else resolve(chunks);
    });
  });
  req.on('error', reject);
  req.on('timeout', () => { req.destroy(); reject(new Error('AI request timed out')); });
  if (body) req.write(body);
  req.end();
});

const response = JSON.parse(data);
return [{ json: { provider, response } }];

const { provider, response } = $input.first().json;
let text;
switch (provider) {
  case 'anthropic': text = response.content && response.content[0] ? response.content[0].text : ''; break;
  case 'openai': text = response.choices && response.choices[0] ? response.choices[0].message.content : ''; break;
  case 'gemini': text = response.candidates && response.candidates[0] ? response.candidates[0].content.parts[0].text : ''; break;
  default: text = response.response || '';
}
return [{ json: { response: text } }];

const raw = $input.first().json.response || '';
const cleaned = raw.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim();
const input = $('Parse Input').item.json;

let parsed;
try { parsed = JSON.parse(cleaned); } catch(e) {
  return [{ json: { success: false, error: 'Failed to parse AI response: ' + e.message, raw: raw.substring(0, 500) } }];
}

const scenario = parsed.scenario || {};
const ability = parsed.ability || {};
const adversary = parsed.adversary || {};

// Generate unique IDs
const ts = Date.now().toString().slice(-6);
const scenarioId = 'SCN-AI-' + ts;
const abilityId = 'custom-a1-' + ts;
const adversaryId = 'custom-' + ts;

// Build CALDERA ability payload
const calderaAbility = {
  ability_id: abilityId,
  name: scenarioId + ' | ' + (scenario.title || 'Custom Scenario'),
  description: scenario.description || '',
  tactic: ability.tactic || 'execution',
  technique_id: ability.technique_id || '',
  technique_name: ability.technique_name || '',
  executors: [{
    name: 'psh',
    platform: 'windows',
    command: (ability.powershell || 'Write-Output "No command generated"').replace(/\\n/g, '\n'),
    cleanup: []
  }]
};

// Build CALDERA adversary payload
const calderaAdversary = {
  adversary_id: adversaryId,
  name: scenarioId + ' | ' + (adversary.name || scenario.title || 'Custom'),
  description: adversary.description || scenario.description || '',
  atomic_ordering: [abilityId],
  tags: ['custom', 'ai-generated', input.product]
};

// Build scenario entry
const scenarioEntry = {
  id: scenarioId,
  product: input.product,
  title: scenario.title || 'Custom Scenario',
  description: scenario.description || '',
  mitre_tactics: scenario.mitre_tactics || [],
  mitre_techniques: scenario.mitre_techniques || [],
  tools: scenario.tools || [],
  atomic_tests: [],
  caldera_ability: adversaryId,
  caldera_adversary_id: adversaryId,
  caldera_group: 'red',
  audience: 'Technical',
  platform: 'windows',
  execution_engine: 'caldera',
  expected_detections: scenario.expected_detections || [],
  talking_points: scenario.talking_points || { universal: [] },
  se_runbook: scenario.se_runbook || {},
  status: 'approved',
  launchable: true,
  source: 'ai-enriched',
  submitted_by: 'Scenario Studio',
  submitted_at: input.timestamp,
  expires_at: null,
  session_id: null
};

return [{ json: { calderaAbility, calderaAdversary, scenarioEntry } }];

const { execSync } = require('child_process');
const data = $input.first().json;

const CALDERA_URL = 'http://172.20.0.10:8888';
const API_KEY = 'MDRLABRED';

// Helper to call CALDERA API
function calderaPost(path, payload) {
  const fs = require('fs');
  const script = JSON.stringify(payload);
  fs.writeFileSync('/tmp/_caldera_payload.json', script);
  try {
    const result = execSync(
      `curl -s -X POST "${CALDERA_URL}/api/v2${path}" -H "KEY: ${API_KEY}" -H "Content-Type: application/json" -d @/tmp/_caldera_payload.json`,
      { encoding: 'utf-8', timeout: 15000 }
    );
    return JSON.parse(result);
  } catch(e) {
    return { error: e.message };
  }
}

// Create ability
const abilityResult = calderaPost('/abilities', data.calderaAbility);
const abilityOk = !abilityResult.error;

// Create adversary
const adversaryResult = calderaPost('/adversaries', data.calderaAdversary);
const adversaryOk = !adversaryResult.error;

return [{ json: { 
  ...data, 
  caldera_loaded: abilityOk && adversaryOk,
  ability_result: abilityOk ? 'created' : abilityResult.error,
  adversary_result: adversaryOk ? 'created' : adversaryResult.error
} }];

const fs = require('fs');
const filePath = '/data/scenarios/scenarios.json';
let db;
try { db = JSON.parse(fs.readFileSync(filePath, 'utf8')); } catch(e) { db = { version: '1.1', last_updated: '', scenarios: [] }; }
const s = $input.first().json.scenarioEntry;
const idx = db.scenarios.findIndex(x => x.id === s.id);
if (idx >= 0) { db.scenarios[idx] = s; } else { db.scenarios.push(s); }
db.last_updated = new Date().toISOString().split('T')[0];
fs.writeFileSync(filePath, JSON.stringify(db, null, 2), 'utf8');
return [{ json: { 
  success: true, 
  scenario_id: s.id, 
  title: s.title,
  launchable: s.launchable,
  caldera_loaded: $input.first().json.caldera_loaded,
  total_scenarios: db.scenarios.length 
} }];

const input = $('Parse Input').item.json;
const ts = Date.now().toString().slice(-6);
const scenarioId = 'SCN-MAN-' + ts;

const scenarioEntry = {
  id: scenarioId,
  product: input.product,
  title: input.name || 'Custom Scenario',
  description: input.description || '',
  mitre_tactics: input.tactics,
  mitre_techniques: input.techniques.map(t => ({ id: t, name: t })),
  tools: input.tools,
  atomic_tests: [],
  caldera_ability: '',
  caldera_adversary_id: '',
  caldera_group: 'red',
  audience: 'Technical',
  platform: 'windows',
  execution_engine: 'caldera',
  expected_detections: [],
  talking_points: { universal: [] },
  se_runbook: {},
  status: 'approved',
  launchable: false,
  source: 'hand-authored',
  submitted_by: 'Scenario Studio',
  submitted_at: input.timestamp,
  expires_at: null,
  session_id: null
};

// Write to scenarios.json
const fs = require('fs');
const filePath = '/data/scenarios/scenarios.json';
let db;
try { db = JSON.parse(fs.readFileSync(filePath, 'utf8')); } catch(e) { db = { version: '1.1', last_updated: '', scenarios: [] }; }
db.scenarios.push(scenarioEntry);
db.last_updated = new Date().toISOString().split('T')[0];
fs.writeFileSync(filePath, JSON.stringify(db, null, 2), 'utf8');

return [{ json: { success: true, scenario_id: scenarioId, title: scenarioEntry.title, launchable: false, note: 'Manual scenario created. Link a CALDERA adversary ID to make it launchable.', total_scenarios: db.scenarios.length } }];
